      "isEnd": true,
      "isSuccess": false
    },
    "fail_leak_private": {
      "text": "❌ Chưa đúng. Dù là nhóm chat kín, chia sẻ ảnh dìm không có sự đồng thuận vẫn có nguy cơ rò rỉ và gây tổn thương cho bạn mình.",
      "isEnd": true,
